# Scratch: مثل بلوک «اگر آنگاه» هست
hava = input("هوا چطوره؟ (آفتابی/بارونی): ")
if hava == "آفتابی":
    print("بریم بیرون بازی کنیم!")
else:
    print("بریم توی خونه برنامه‌نویسی کنیم!")

# Scratch: مثل بلوک «اگر آنگاه وگرنه اگر آنگاه» هست
saat = int(input("ساعت چنده؟ (0 تا 23): "))
if saat < 10:
    print("صبح بخیر!")
elif saat < 17:
    print("روز بخیر!")
else:
    print("شب بخیر!")

